#include <hip/hip_runtime.h>
#include <cstdio>
#include <cstdlib>
#include <cstring>
#include <algorithm>
#include <vector>

static void check(hipError_t e, const char* file, int line) {
    if (e != hipSuccess) {
        fprintf(stderr, "HIP error at %s:%d: %s\n", file, line, hipGetErrorString(e));
        exit(1);
    }
}
#define CHECK(cmd) check(cmd, __FILE__, __LINE__)

__global__ void __launch_bounds__(256)
read_kernel(const float4* __restrict__ data,
            float* __restrict__ partial_sums,
            size_t num_float4)
{
    const size_t tid = (size_t)blockIdx.x * blockDim.x + threadIdx.x;
    const size_t stride = (size_t)gridDim.x * blockDim.x;

    float acc = 0.0f;
    for (size_t i = tid; i < num_float4; i += stride) {
        float4 v = data[i];
        acc += v.x + v.y + v.z + v.w;
    }

    for (int offset = 32; offset > 0; offset >>= 1)
        acc += __shfl_down(acc, offset);

    __shared__ float smem[4];
    const int lane = threadIdx.x & 63;
    const int wid = threadIdx.x >> 6;

    if (lane == 0) smem[wid] = acc;
    __syncthreads();

    if (wid == 0) {
        acc = (lane < 4) ? smem[lane] : 0.0f;
        for (int offset = 2; offset > 0; offset >>= 1)
            acc += __shfl_down(acc, offset);
        if (lane == 0)
            partial_sums[blockIdx.x] = acc;
    }
}

int main() {
    const size_t buffer_bytes = 4ULL * 1024 * 1024 * 1024;
    const size_t num_float4 = buffer_bytes / sizeof(float4);
    const int threads_per_block = 256;
    const int num_blocks = 4096;
    const int warmup_iters = 5;
    const int timed_iters = 100;

    float4* d_data;
    float* d_sums;
    CHECK(hipMalloc(&d_data, buffer_bytes));
    CHECK(hipMalloc(&d_sums, num_blocks * sizeof(float)));
    CHECK(hipMemset(d_data, 0, buffer_bytes));

    float* h_sums = (float*)malloc(num_blocks * sizeof(float));

    hipEvent_t start, stop;
    CHECK(hipEventCreate(&start));
    CHECK(hipEventCreate(&stop));

    for (int i = 0; i < warmup_iters; i++) {
        hipLaunchKernelGGL(read_kernel, dim3(num_blocks), dim3(threads_per_block), 0, 0,
                           d_data, d_sums, num_float4);
        CHECK(hipDeviceSynchronize());
    }

    std::vector<float> times(timed_iters);
    for (int i = 0; i < timed_iters; i++) {
        CHECK(hipEventRecord(start, 0));
        hipLaunchKernelGGL(read_kernel, dim3(num_blocks), dim3(threads_per_block), 0, 0,
                           d_data, d_sums, num_float4);
        CHECK(hipEventRecord(stop, 0));
        CHECK(hipEventSynchronize(stop));
        CHECK(hipEventElapsedTime(×[i], start, stop));
    }

    std::sort(times.begin(), times.end());
    float median_ms = times[timed_iters / 2];

    double bw_gbps = (double)buffer_bytes / (median_ms / 1000.0) / 1e9;

    CHECK(hipMemcpy(h_sums, d_sums, num_blocks * sizeof(float), hipMemcpyDeviceToHost));
    float checksum = 0;
    for (int i = 0; i < num_blocks; i++) checksum += h_sums[i];

    printf("HBM_BANDWIDTH_GBPS=%.2f\n", bw_gbps);
    printf("buffer_bytes=%zu\n", buffer_bytes);
    printf("median_kernel_time_ms=%.6f\n", median_ms);
    printf("checksum=%f\n", checksum);

    CHECK(hipEventDestroy(start));
    CHECK(hipEventDestroy(stop));
    CHECK(hipFree(d_data));
    CHECK(hipFree(d_sums));
    free(h_sums);
    return 0;
}

